<template>
    <div>
        <!-- 面包屑导航 -->
    <el-breadcrumb separator-class="el-icon-arrow-right">
    <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
    <el-breadcrumb-item>商品管理</el-breadcrumb-item>
    <el-breadcrumb-item>商品列表</el-breadcrumb-item>
    </el-breadcrumb>
    <!-- 卡片视图区域 -->
    <el-card>
      <el-row :gutter="20">
        <el-col :span="8">
          <!-- v-model 绑定数据，从而实现数据搜索 -->
          <el-input placeholder="请输入内容" v-model="queryInfo.query" clearable @clear="getGoodsList">
          <el-button slot="append" icon="el-icon-search" @click="getGoodsList"></el-button>
          </el-input>
        </el-col>
        <el-col :span="4">
          <el-button type="primary" @click="goAddpage">添加商品</el-button>
        </el-col>
      </el-row>
      <!-- table表格区域 -->
      <el-table :data="goodslist" border stripe>
        <el-table-column type="index"></el-table-column>
        <el-table-column label="商品名称" prop="goods_name"></el-table-column>
        <el-table-column label="商品价格(元)" prop="goods_price" width="95px"></el-table-column>
        <el-table-column label="商品重量" prop="goods_weight" width="70px"></el-table-column>
        <el-table-column label="创建时间" prop="add_time" width="140px">
          <template slot-scope="scope">
            {{scope.row.add_time | dateFormat}}
          </template>
        </el-table-column>
        <el-table-column label="操作" width="130px">
          <template slot-scope="scope">
            <el-button type="primary" icon="el-icon-edit" size="mini" @click="showEditDialog(scope.row.goods_id)"></el-button>
            <el-button type="danger" icon="el-icon-delete" size="mini" @click="removeById(scope.row.goods_id)"></el-button>
          </template>
        </el-table-column>
      </el-table>
      <!-- 分页区域 -->
       <el-pagination
      @size-change="handleSizeChange"
      @current-change="handleCurrentChange"
      :current-page="queryInfo.pagenum"
      :page-sizes="[5, 10, 15, 20]"
      :page-size="queryInfo.pagesize"
      layout="total, sizes, prev, pager, next, jumper"
      :total="total" background>
    </el-pagination>
    </el-card>
<!-- 修改对话框 -->
<el-dialog
          title="修改信息"
          :visible.sync="editDialogVisible"
          @close="editDialogClosed"
          width="80%">
    <el-card>
        <!-- 提示区域 -->
            <el-alert
            title="修改商品信息"
            type="info"
            center
            show-icon
            :closable="false">
            </el-alert>
            <!-- 步骤条区域  这里的是数据绑定 数据联动效果-->
            <el-steps :space="200" :active="activeIndex - 0" finish-status="success" align-center>
            <el-step title="基本信息"></el-step>
            <el-step title="商品参数"></el-step>
            <el-step title="商品属性"></el-step>
            <el-step title="商品图片"></el-step>
            <el-step title="商品内容"></el-step>
            <el-step title="完成"></el-step>
            </el-steps>
            <!-- Tab栏区域 v-model与name的值绑定 这里是字符串
            :tab-position 指定label的位置-->
            <el-form  :model="editForm" :rules="editFormRules" ref="editFormRef" label-width="100px" label-position="top">
            <el-tabs  v-model="activeIndex" :tab-position="'left'" :before-leave="beforeTabLeave"
            @tab-click="tabClicked">
              <el-tab-pane label="基本信息" name="0">
                  <el-form-item label="商品名称" prop="goods_name" style="text-align: left">
                      <el-input v-model="editForm.goods_name"></el-input>
                  </el-form-item>
                  <el-form-item label="商品价格" prop="goods_price" style="text-align: left">
                      <el-input v-model="editForm.goods_price" type="number"></el-input>
                  </el-form-item>
                  <el-form-item label="商品重量" prop="goods_weight" style="text-align: left">
                      <el-input v-model="editForm.goods_weight" type="number"></el-input>
                  </el-form-item>
                  <el-form-item label="商品数量" prop="goods_number" style="text-align: left">
                      <el-input v-model="editForm.goods_number" type="number"></el-input>
                  </el-form-item>
              </el-tab-pane>
              <el-tab-pane label="商品参数" name="1">
              <!-- 渲染表单的item项 -->
               <el-form-item :label="item.attr_name" v-for="item in manyTableData" :key="item.attr_id">
                   <!-- 复选框组 -->
                   <el-checkbox-group v-model="item.attr_vals">
                        <el-checkbox :label="cb" v-for="(cb, i) in item.attr_vals" :key="i" border></el-checkbox>
                    </el-checkbox-group>
               </el-form-item>
              </el-tab-pane>
              <el-tab-pane label="商品属性" name="2">
                <el-form-item :label="item.attr_name" v-for="item in onlyTableData" :key="item.attr_id">
                  <el-input v-model="item.attr_vals"></el-input>
                </el-form-item>
              </el-tab-pane>
              <el-tab-pane label="商品图片" name="3">
                <!-- action 表示图片要上传到的后台API接口地址 -->
                <el-upload
                    :action="uploadURL"
                    :on-preview="handlePreview"
                    :on-remove="handleRemove"
                    :headers="headersObj"
                    list-type="picture"
                    :on-success="handleSuccess">
                    <el-button size="small" type="primary">点击上传</el-button>
                </el-upload>
              </el-tab-pane>
              <el-tab-pane label="商品内容" name="4">
                <!-- 富文本编辑器组件 -->
                <quill-editor v-model="editForm.goods_introduce"></quill-editor>
                <!-- 添加商品的按钮 -->
                <el-button type="primary" class="btnedit" @click="edit">添加商品</el-button>
              </el-tab-pane>
            </el-tabs>
            </el-form>
    </el-card>
    </el-dialog>
    <!-- 图片预览 -->
        <el-dialog
          title="图片预览"
          :visible.sync="previewVisible"
          width="50%">
          <img :src="previewPath" class="previewImg">
        </el-dialog>
    </div>
</template>

<script>
export default {
  data () {
    return {
      activeIndex: '0',
      // 查询参数列表
      queryInfo: {
        query: '',
        pagenum: 1,
        pagesize: 10
      },
      // 商品列表
      goodslist: [],
      // 总数据条数
      total: 0,
      editForm: {
        goods_name: '',
        goods_price: 0,
        goods_weight: 0,
        goods_number: 0,
        // 图片数组
        pics: [],
        // 商品的详情描述
        goods_introduce: '',
        attrs: []
      },
      editFormRules: {
        goods_name: [
          { required: true, message: '请输入商品名称！', trigger: 'blur' }
        ],
        goods_price: [
          { required: true, message: '请输入商品价格', trigger: 'blur' }
        ],
        goods_weight: [
          { required: true, message: '请输入商品重量', trigger: 'blur' }
        ],
        goods_number: [
          { required: true, message: '请输入商品数量', trigger: 'blur' }
        ]
      },
      // 控制修改用户对话框的显示与隐藏
      editDialogVisible: false,
      // 商品分类列表
      catelist: [],
      cateProps: {
        value: 'cat_id',
        label: 'cat_name',
        children: 'children'
      },
      // 动态参数列表数据
      manyTableData: [],
      // 静态属性列表
      onlyTableData: [],
      // 上传图片的URL地址
      uploadURL: 'http://127.0.0.1:8888/api/private/v1/upload',
      // 图片上传组件的headers请求头对象
      headersObj: {
        Authorization:
        window.sessionStorage.getItem('token')
      },
      previewPath: '',
      previewVisible: false
    }
  },
  created () {
    this.getGoodsList()
    this.getCateList()
  },
  methods: {
    // 获取所有商品分类数据
    async getCateList () {
      const { data: res } = await this.$http.get('categories')
      if (res.meta.status !== 200) { return this.$message.error('获取商品分类数据失败!') }
      this.catelist = res.data
    },
    // 根据分页获取对应的商品列表
    async getGoodsList () {
      const { data: res } = await this.$http.get('goods', { params: this.queryInfo })
      if (res.meta.status !== 200) { return this.$message.error('获取商品列表失败!') }
      this.$message.success('获取商品列表成功!')
      console.log(res.data)
      this.goodslist = res.data.goods
      this.total = res.data.total
    },
    handleSizeChange (newSize) {
      this.queryInfo.pagesize = newSize
      this.getGoodsList()
    },
    handleCurrentChange (newPages) {
      this.queryInfo.pagenum = newPages
      this.getGoodsList()
    },
    async removeById (id) {
      const confirmResult = await this.$confirm('此操作将永久删除该商品, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).catch(err => err)
      if (confirmResult !== 'confirm') { return this.$message.info('已经取消删除!') }
      const { data: res } = await this.$http.delete(`goods/${id}`)
      if (res.meta.status !== 200) { return this.$message.error('删除失败!') }
      this.$message.success('删除成功！')
      this.getGoodsList()
    },
    // 跳转到指定路由
    goAddpage () {
      this.$router.push('/goods/add')
    },
    // 展示编辑用户的对话框
    async showEditDialog (id) {
      const { data: res } = await this.$http.get('goods/' + id)
      if (res.meta.status !== 200) {
        return this.$message.error('查询用户信息失败！')
      }
      this.editDialogVisible = true
      this.editForm = res.data
    },
    // 监听修改用户对话框的关闭事件
    editDialogClosed () {
      this.$refs.editFormRef.resetFields()
    },
    // 处理图片预览效果
    handlePreview (file) {
      this.previewPath = file.response.data.url
      this.previewVisible = true
    },
    // 处理移除图片的操作
    handleRemove (file) {
      // 获取将要删除的图片的零时路径
      const filePath = file.response.data.tmp_path
      // 从PICS数组中，找到这个图片对应的索引值
      const i = this.editForm.pics.findIndex(x => x.pic === filePath)
      // 调用数组的splice方法，把图片信息对象，从PICS数组中移除
      this.editForm.pics.splice(i, 1)
    },
    // 监听图片上传成功的事件
    handleSuccess (response) {
      // 拼接得到一个图片信息对象
      const picInfo = { pic: response.data.tmp_path }
      // 将图片信息对象，push 到PICS数组中
      this.editForm.pics.push(picInfo)
    }
  },
  computed: {
    // 计算属性
    cateId () {
      if (this.editForm.goods_cat.length === 3) {
        return this.editForm.goods_cat[2]
      }
      return null
    }
  }
}
</script>

<style lang="less" scoped>
.el-checkbox {
    margin: 0 10px 0 0 !important;
}
.previewImg {
  width: 100%;
}
.btnedit {
  margin: 15px;
}
</style>
